PROGRAM TankLevelMonitor
VAR_INPUT
    rawLevel      : INT;
    highAlarmSP   : REAL;
    lowAlarmSP    : REAL;
    hysteresis    : REAL;
END_VAR
VAR_OUTPUT
    levelPct      : REAL;
    highAlarm     : BOOL;
    lowAlarm      : BOOL;
END_VAR
VAR
    firstScan : BOOL := FALSE;
END_VAR

IF NOT firstScan THEN
    highAlarmSP := 85.0;
    lowAlarmSP := 15.0;
    hysteresis := 2.0;
    firstScan := TRUE;
END_IF;

levelPct := INT_TO_REAL(rawLevel) / 276.48;

IF levelPct >= highAlarmSP THEN
    highAlarm := TRUE;
ELSIF levelPct < highAlarmSP - hysteresis THEN
    highAlarm := FALSE;
END_IF;

IF levelPct <= lowAlarmSP THEN
    lowAlarm := TRUE;
ELSIF levelPct > lowAlarmSP + hysteresis THEN
    lowAlarm := FALSE;
END_IF;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn : BOOL;
    Overload : BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor : BOOL;
    Star_Contactor : BOOL;
    Delta_Contactor : BOOL;
    Fault : BOOL;
END_VAR
VAR
    startEdge : R_TRIG;
    runTimer : TON;
    motorRunning : BOOL;
    starPhase : BOOL;
    deltaPhase : BOOL;
END_VAR

startEdge(CLK := Start_btn);
runTimer(IN := motorRunning AND starPhase, PT := T#3s);

IF startEdge.Q AND NOT Stop_btn AND NOT Overload THEN
    motorRunning := TRUE;
    starPhase := TRUE;
    deltaPhase := FALSE;
ELSIF Stop_btn OR Overload THEN
    motorRunning := FALSE;
    starPhase := FALSE;
    deltaPhase := FALSE;
END_IF;

IF runTimer.Q THEN
    starPhase := FALSE;
    deltaPhase := TRUE;
END_IF;

Main_Contactor := motorRunning;
Star_Contactor := motorRunning AND starPhase;
Delta_Contactor := motorRunning AND deltaPhase;
Fault := Overload;

END_PROGRAM

TYPE
    ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    startCmd : BOOL;
    sensorPresent : BOOL;
    sensorDefect : BOOL;
    eStop : BOOL;
END_VAR

VAR_OUTPUT
    motorRun : BOOL;
    rejectSolenoid : BOOL;
END_VAR

VAR
    state : ConveyorState := ST_IDLE;
    rejectTimer : TON;
END_VAR

(* EStop handling - highest priority *)
IF eStop THEN
    state := ST_FAULT;
    motorRun := FALSE;
    rejectSolenoid := FALSE;
    rejectTimer(IN := FALSE);
    RETURN;
END_IF;

(* Exit from FAULT when EStop is cleared *)
IF state = ST_FAULT THEN
    state := ST_IDLE;
    motorRun := FALSE;
    rejectSolenoid := FALSE;
    rejectTimer(IN := FALSE);
    RETURN;
END_IF;

CASE state OF
    ST_IDLE:
        motorRun := FALSE;
        rejectSolenoid := FALSE;
        rejectTimer(IN := FALSE);
        IF startCmd THEN
            state := ST_RUNNING;
        END_IF;

    ST_RUNNING:
        motorRun := TRUE;
        rejectSolenoid := FALSE;
        rejectTimer(IN := FALSE);
        IF sensorPresent AND sensorDefect THEN
            state := ST_REJECTING;
            rejectTimer(IN := TRUE, PT := T#500ms);
        END_IF;

    ST_REJECTING:
        motorRun := FALSE;
        rejectSolenoid := TRUE;
        rejectTimer(IN := TRUE);
        IF rejectTimer.Q THEN
            state := ST_RUNNING;
            rejectTimer(IN := FALSE);
        END_IF;
END_CASE;
END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
  Enable : BOOL;
  Setpoint : REAL;
  ProcessValue : REAL;
  Kp : REAL := 2.0;
  Ki : REAL := 0.05;
  Kd : REAL := 0.0;
  CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
  Output : REAL;
END_VAR
VAR
  integral : REAL := 0.0;
  ePrev : REAL := 0.0;
END_VAR
VAR_TEMP
  ts : REAL;
  e : REAL;
  p : REAL;
  i : REAL;
  d : REAL;
END_VAR
BEGIN
  ts := TIME_TO_REAL(CycleTime);
  IF NOT Enable THEN
    Output := 0.0;
    integral := 0.0;
    ePrev := 0.0;
  ELSE
    e := Setpoint - ProcessValue;
    p := Kp * e;
    integral := integral + Ki * ts * e;
    i := integral;
    IF ts > 0.0 THEN
      d := Kd * (e - ePrev) / ts;
    ELSE
      d := 0.0;
    END_IF;
    Output := p + i + d;
    ePrev := e;
  END_IF;
  IF Output > 100.0 THEN
    Output := 100.0;
  ELSIF Output < 0.0 THEN
    Output := 0.0;
  END_IF;
END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR

VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR

VAR
    leadPump : INT := 1;
END_VAR

(* Manual Mode *)
IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    (* Auto Mode *)
    (* Fault handling: switch leadPump to the non-faulted pump *)
    IF Pump1Fault THEN
        leadPump := 2;
    ELSIF Pump2Fault THEN
        leadPump := 1;
    END_IF;

    (* Level control *)
    IF LevelLow THEN
        IF leadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSIF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;

END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
  StartSeq : BOOL;
  Abort : BOOL;
END_VAR
VAR_OUTPUT
  Valve1 : BOOL;
  Valve2 : BOOL;
  Valve3 : BOOL;
  SeqDone : BOOL;
  SeqActive : BOOL;
END_VAR
VAR RETAIN
  Step : INT := 0;
END_VAR
VAR
  Timer1 : TON;
  Timer2 : TON;
  Timer3 : TON;
END_VAR

IF Abort THEN
  Step := 0;
  Valve1 := FALSE;
  Valve2 := FALSE;
  Valve3 := FALSE;
  SeqDone := FALSE;
  SeqActive := FALSE;
  Timer1(IN := FALSE);
  Timer2(IN := FALSE);
  Timer3(IN := FALSE);
ELSE
  CASE Step OF
    0:
      Valve1 := FALSE;
      Valve2 := FALSE;
      Valve3 := FALSE;
      SeqDone := FALSE;
      SeqActive := FALSE;
      Timer1(IN := FALSE);
      Timer2(IN := FALSE);
      Timer3(IN := FALSE);
      IF StartSeq THEN
        Step := 1;
      END_IF;
    1:
      Valve1 := TRUE;
      Valve2 := FALSE;
      Valve3 := FALSE;
      SeqDone := FALSE;
      SeqActive := TRUE;
      Timer1(IN := TRUE, PT := T#2s);
      IF Timer1.Q THEN
        Step := 2;
        Timer1(IN := FALSE);
      END_IF;
    2:
      Valve1 := FALSE;
      Valve2 := TRUE;
      Valve3 := FALSE;
      SeqDone := FALSE;
      SeqActive := TRUE;
      Timer2(IN := TRUE, PT := T#3s);
      IF Timer2.Q THEN
        Step := 3;
        Timer2(IN := FALSE);
      END_IF;
    3:
      Valve1 := FALSE;
      Valve2 := FALSE;
      Valve3 := TRUE;
      SeqDone := FALSE;
      SeqActive := TRUE;
      Timer3(IN := TRUE, PT := T#1s);
      IF Timer3.Q THEN
        Step := 4;
        Timer3(IN := FALSE);
      END_IF;
    4:
      Valve1 := FALSE;
      Valve2 := FALSE;
      Valve3 := FALSE;
      SeqDone := TRUE;
      SeqActive := FALSE;
      Timer1(IN := FALSE);
      Timer2(IN := FALSE);
      Timer3(IN := FALSE);
  END_CASE;
END_IF;
END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR

VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR

VAR
    ResetTrig : R_TRIG;
END_VAR

ResetTrig(CLK := ResetPB);

IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
ELSIF ResetTrig.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
  productSensor : BOOL;
  resetBatch : BOOL;
  batchTarget : INT := 1000;
END_VAR
VAR_OUTPUT
  batchCount : INT;
  batchComplete : BOOL;
  totalCount : INT;
END_VAR
VAR
  sensorEdge : R_TRIG;
  batchCounter : CTU;
END_VAR

sensorEdge(CLK := productSensor);
batchCounter(CU := sensorEdge.Q, R := resetBatch, PV := batchTarget);

batchCount := batchCounter.CV;
batchComplete := batchCounter.Q;

IF sensorEdge.Q THEN
  totalCount := totalCount + 1;
END_IF;

END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
  enable : BOOL;
  rawInput : REAL;
  windowSize : INT;
END_VAR
VAR_OUTPUT
  filtered : REAL;
END_VAR
VAR
  buffer : ARRAY[0..9] OF REAL;
  head : INT;
  count : INT;
  sum : REAL;
  effectiveSize : INT;
  i : INT;
END_VAR

(* Clamp windowSize to 1..10 *)
IF windowSize < 1 THEN
  effectiveSize := 1;
ELSIF windowSize > 10 THEN
  effectiveSize := 10;
ELSE
  effectiveSize := windowSize;
END_IF;

IF NOT enable THEN
  FOR i := 0 TO 9 DO
    buffer[i] := 0.0;
  END_FOR;
  head := 0;
  count := 0;
  sum := 0.0;
  filtered := 0.0;
ELSE
  sum := sum + rawInput;

  IF count < effectiveSize THEN
    count := count + 1;
  ELSE
    sum := sum - buffer[head];
  END_IF;

  buffer[head] := rawInput;

  head := head + 1;
  IF head >= 10 THEN
    head := 0;
  END_IF;

  filtered := sum / INT_TO_REAL(count);
END_IF;

END_FUNCTION_BLOCK
